import math

def euler_totient(n: int) -> int:
    if n <= 0:
        raise ValueError("Input must be a positive integer.")
    if n == 1:
        return 1

    result = n
    temp_n = n

    p = 2
    while p * p <= temp_n:
        if temp_n % p == 0:
            result -= result // p
            while temp_n % p == 0:
                temp_n //= p
        p += 1

    if temp_n > 1:
        result -= result // temp_n

    return result
